  messages: Message[],
  windowIndex: number
): string {
  const roles = messages.map((m) => m.role);
  const roleCounts = roles.reduce((acc, role) => {
    acc[role] = (acc[role] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const contentPreview = messages
    .map((m) => (m.content || "").slice(0, 50))
    .filter((c) => c.length > 0)
    .join(" | ");

