  const windowSummaries: string[] = [];
  let archivedId: string | null = null;

  for (let i = 0; i < windows.length; i++) {
    const win = windows[i];
    const summary = summarizeWindow(win.messages, win.messages.length);
    windowSummaries.push(`Window ${i}: ${summary}`);
  }

  // Create archive entity in KnowledgeGraph
  if (windowSummaries.length > 0) {
    try {
      const archiveResult = await knowledge.addEntity(
        `session_compaction_${Date.now()}`,
        "session_archive",
        [
          `Session context archive from compaction`,
          `Original messages: ${originalCount}`,
          `Compacted into ${windows.length} windows`,
          `Summaries:\n${windowSummaries.join("\n")}`,
